B.b0=new A.la("\u0130spat ve Deliller",B.kU,0,"ispatDeliller")
B.EJ=s(["Sabittir, yaln\u0131zca kanun de\u011fi\u015fikli\u011fiyle artar.","Her takvim y\u0131l\u0131 ba\u015f\u0131nda yeniden de\u011ferleme oran\u0131nda art\u0131r\u0131l\u0131r.","H\xe2kim her dava i\xe7in ayr\u0131ca takdir eder.","Taraflar s\xf6zle\u015fmeyle serbest\xe7e belirler."],t.s)
B.Km=new A.aX("ispat_02",B.b0,"Senetle ispat zorunlulu\u011fundaki parasal s\u0131n\u0131r nas\u0131l belirlenir?",B.EJ,1,"S\u0131n\u0131r her takvim y\u0131l\u0131 ba\u015f\u0131ndan ge\xe7erli olmak \xfczere \xf6nceki y\u0131la ili\u015fkin yeniden de\u011ferleme oran\u0131nda art\u0131r\u0131l\u0131r. G\xfcncel TL tutar\u0131n\u0131 ilgili y\u0131l\u0131n oran\u0131na g\xf6re teyit et.")
B.EM=s(["Her h\xe2lde tan\u0131kla ispatlanabilir.","Miktar\u0131na bak\u0131lmaks\u0131z\u0131n senetle ispatlanmas\u0131 gerekir; tan\u0131k dinlenemez.","Yaln\u0131zca yeminle ispatlan\u0131r.","Hi\xe7bir \u015fekilde ispatlanamaz."],t.s)
B.KJ=new A.aX("ispat_03",B.b0,'Senede ba\u011fl\u0131 bir iddiaya kar\u015f\u0131 ileri s\xfcr\xfclen "senede ayk\u0131r\u0131" bir savunma, s\u0131n\u0131r\u0131n alt\u0131nda kalsa bile nas\u0131l ispatlan\u0131r?',B.EM,1,"HMK m. 201 (senede kar\u015f\u0131 tan\u0131kla ispat yasa\u011f\u0131): Senede ba\u011fl\u0131 her t\xfcr iddiaya kar\u015f\u0131 ileri s\xfcr\xfclen ve senedin h\xfck\xfcm ve kuvvetini ortadan kald\u0131racak/azaltacak iddialar, miktar ne olursa olsun tan\u0131kla ispatlanamaz.")
B.Ga=s(["Hi\xe7bir delil kabul edilmez.","Tan\u0131k dinlenebilir.","Dava reddedilir.","Yaln\u0131zca bilirki\u015fi incelemesi yap\u0131l\u0131r."],t.s)
B.Ko=new A.aX("ispat_04",B.b0,'Senetle ispat zorunlulu\u011fu bulunan bir h\xe2lde "delil ba\u015flang\u0131c\u0131" varsa sonu\xe7 ne olur?',B.Ga,1,"HMK m. 202: Delil ba\u015flang\u0131c\u0131 varsa tan\u0131k dinlenebilir. Delil ba\u015flang\u0131c\u0131; iddia edilen i\u015flemi tamamen ispata yetmemekle birlikte onu muhtemel g\xf6steren ve aleyhine ileri s\xfcr\xfclen ki\u015fi (veya temsilcisi) taraf\u0131ndan verilmi\u015f yaz\u0131l\u0131 belgedir.")
B.Gf=s(["\u0130ki tacir aras\u0131ndaki yaz\u0131l\u0131 s\xf6zle\u015fmede","Altsoy\u2013\xfcstsoy, e\u015fler ve karde\u015fler aras\u0131ndaki i\u015flemlerde","Resm\xee senede dayanan alacaklarda","Noterde d\xfczenlenen i\u015flemlerde"],t.s)
B.K5=new A.aX("ispat_05",B.b0,"A\u015fa\u011f\u0131dakilerden hangisinde senetle ispat zorunlulu\u011funa ra\u011fmen tan\u0131k dinlenebilir?",B.Gf,1,"HMK m. 203: Altsoy-\xfcstsoy, e\u015fler, karde\u015fler aras\u0131ndaki i\u015flemler; hukuki i\u015flemlerde irade fesad\u0131 (hata, hile, ikrah) iddialar\u0131; haks\u0131z fiil ve sebepsiz zenginle\u015fme; senedin elde tutulamamas\u0131nda hakl\u0131 sebep gibi h\xe2llerde tan\u0131k dinlenebilir.")
B.Gj=s(["Kamu d\xfczenindendir; h\xe2kim resen g\xf6zetir ve taraf vazge\xe7emez.","Kamu d\xfczeninden de\u011fildir; kar\u015f\u0131 taraf a\xe7\u0131k\xe7a muvafakat ederse tan\u0131k dinlenebilir.","Yaln\u0131zca daval\u0131 lehine getirilmi\u015f bir kurald\u0131r.","Sadece istinaf a\u015famas\u0131nda ileri s\xfcr\xfclebilir."],t.s)
B.Ks=new A.aX("ispat_06",B.b0,"Senetle ispat kural\u0131n\u0131n kamu d\xfczeniyle ili\u015fkisi bak\u0131m\u0131ndan a\u015fa\u011f\u0131dakilerden hangisi do\u011frudur?",B.Gj,1,"HMK m. 200/2: Senetle ispat zorunlulu\u011fu kamu d\xfczeninden de\u011fildir. Kar\u015f\u0131 taraf a\xe7\u0131k muvafakat verirse (tan\u0131k dinlenmesine itiraz etmezse) s\u0131n\u0131r\u0131n \xfczerindeki i\u015flemde dahi tan\u0131k dinlenebilir.")
B.Fa=s(["Hi\xe7 kimse tan\u0131kl\u0131ktan \xe7ekinemez.","Taraflardan birinin ni\u015fanl\u0131s\u0131 veya belirli derecedeki h\u0131s\u0131mlar\u0131 tan\u0131kl\u0131ktan \xe7ekinebilir.","Tan\u0131kl\u0131ktan yaln\u0131zca kamu g\xf6revlileri \xe7ekinebilir.","Tan\u0131kl\u0131ktan \xe7ekinme yaln\u0131zca ceza davalar\u0131nda m\xfcmk\xfcnd\xfcr."],t.s)
B.KA=new A.aX("ispat_07",B.b0,"Tan\u0131kl\u0131ktan \xe7ekinme hakk\u0131 bak\u0131m\u0131ndan a\u015fa\u011f\u0131dakilerden hangisi s\xf6ylenebilir?",B.Fa,1,"HMK m. 248: \u0130ki taraftan birinin ni\u015fanl\u0131s\u0131; evlilik ba\u011f\u0131 kalmasa da e\u015fi; belirli derecedeki kan ve kay\u0131n h\u0131s\u0131mlar\u0131 ile evlatl\u0131k ba\u011f\u0131 bulunanlar ki\u015fisel sebeplerle tan\u0131kl\u0131ktan \xe7ekinebilir (m. 249\u2013250: s\u0131r ve menfaat ihlali sebepleri ayr\u0131ca d\xfczenlenmi\u015ftir).")
B.DM=s(["Teknik bir konunun ayd\u0131nlat\u0131lmas\u0131 gerekti\u011finde","\xc7\xf6z\xfcm\xfc h\xe2kimlik mesle\u011finin gerektirdi\u011fi genel ve hukuki bilgiyle m\xfcmk\xfcn olan konularda","Hesap ve muhasebe incelemesi gerekti\u011finde","T\u0131bbi bir de\u011ferlendirme gerekti\u011finde"],t.s)
B.Kr=new A.aX("ispat_08",B.b0,"Bilirki\u015fiye hangi durumda ba\u015fvurulamaz?",B.DM,1,"HMK m. 266: \xc7\xf6z\xfcm\xfc \xf6zel/teknik bilgiyi gerektiren h\xe2llerde bilirki\u015fiye ba\u015fvurulur; ancak genel bilgi veya hukuki bilgiyle \xe7\xf6z\xfclebilecek konularda (hukukun uygulanmas\u0131 h\xe2kime ait oldu\u011fundan) bilirki\u015fiye ba\u015fvurulamaz.")
B.EL=s(["Rapor kesin delildir; h\xe2kim aynen uymak zorundad\u0131r.","Rapor takdiri delildir; h\xe2kim raporla ba\u011fl\u0131 de\u011fildir, serbest\xe7e de\u011ferlendirir.","H\xe2kim raporu hi\xe7 dikkate alamaz.","H\xe2kim ancak Yarg\u0131tay onay\u0131yla rapordan ayr\u0131labilir."],t.s)
B.Kx=new A.aX("ispat_10",B.b0,"H\xe2kimin bilirki\u015fi raporu kar\u015f\u0131s\u0131ndaki durumu nedir?",B.EL,1,"Bilirki\u015fi raporu takdiri delildir. H\xe2kim raporu serbest\xe7e de\u011ferlendirir ve gerek\xe7esini g\xf6stererek rapordan ayr\u0131labilir; ayr\u0131ca bilirki\u015fi hukuki nitelendirme yapamaz, hukukun uygulanmas\u0131 h\xe2kime aittir.")
B.AH=new A.I(1,1,0.6901960784313725,0.47843137254901963,B.h)
B.bE=new A.la("Ge\xe7ici Hukuki Korumalar",B.AH,1,"geciciKoruma")
B.Fi=s(["Para alacaklar\u0131n\u0131n tahsilinin g\xfcvence alt\u0131na al\u0131nmas\u0131","Uyu\u015fmazl\u0131k konusu (\xe7eki\u015fmeli) \u015fey veya hak hakk\u0131nda koruma sa\u011flanmas\u0131","Bor\xe7lunun hapsen tazyiki","Kesinle\u015fmi\u015f bir karar\u0131n icras\u0131"],t.s)
B.Ke=new A.aX("gecici_01",B.bE,"\u0130htiyati tedbirin konusu a\u015fa\u011f\u0131dakilerden hangisidir?",B.Fi,1,"HMK m. 389: \u0130htiyati tedbir, uyu\u015fmazl\u0131k konusu \u015fey/hak hakk\u0131nda; mevcut durumdaki de\u011fi\u015fme nedeniyle hakka kavu\u015fman\u0131n zorla\u015faca\u011f\u0131/imk\xe2ns\u0131zla\u015faca\u011f\u0131 ya da gecikme y\xfcz\xfcnden ciddi zarar do\u011faca\u011f\u0131 h\xe2llerde verilir. Para alacaklar\u0131n\u0131n g\xfcvencesi ise ihtiyati hacizdir.")
B.FP=s(["\xc7eki\u015fmeli \u015fey i\xe7in; HMK","Rehinle temin edilmemi\u015f bir para alaca\u011f\u0131 i\xe7in; \u0130cra ve \u0130flas Kanunu","Manevi tazminat i\xe7in; TBK","Nafaka i\xe7in; TMK"],t.s)
B.Kc=new A.aX("gecici_02",B.bE,"\u0130htiyati haciz hangi t\xfcr alacaklar i\xe7in istenir ve dayana\u011f\u0131 hangi kanundur?",B.FP,1,"\u0130\u0130K m. 257: \u0130htiyati haciz, rehinle temin edilmemi\u015f ve vadesi gelmi\u015f bir para borcunun alacakl\u0131s\u0131 taraf\u0131ndan istenir (kanunda say\u0131lan h\xe2llerde vadesi gelmemi\u015f alacaklar i\xe7in de m\xfcmk\xfcnd\xfcr). Dayana\u011f\u0131 \u0130cra ve \u0130flas Kanunu\u2019dur.")
B.Eq=s(["\u0130kisi de yaln\u0131zca para alacaklar\u0131 i\xe7indir.","\u0130htiyati tedbir \xe7eki\u015fmeli \u015fey/hak i\xe7in (HMK), ihtiyati haciz para alaca\u011f\u0131 i\xe7in (\u0130\u0130K) \xf6ng\xf6r\xfclm\xfc\u015ft\xfcr.","\u0130htiyati haciz dava a\xe7\u0131lmadan hi\xe7 istenemez.","\u0130htiyati tedbir yaln\u0131zca icra dairesinden istenir."],t.s)
B.Ky=new A.aX("gecici_03",B.bE,"\u0130htiyati tedbir ile ihtiyati haciz aras\u0131ndaki temel fark a\u015fa\u011f\u0131dakilerden hangisidir?",B.Eq,1,"Temel ayr\u0131m konular\u0131ndad\u0131r: \u0130htiyati tedbir para d\u0131\u015f\u0131ndaki \xe7eki\u015fmeli \u015fey/hakk\u0131n korunmas\u0131na (HMK m. 389 vd.), ihtiyati haciz ise para alaca\u011f\u0131n\u0131n g\xfcvenceye al\u0131nmas\u0131na (\u0130\u0130K m. 257 vd.) hizmet eder.")
B.EZ=s(["Hakl\u0131l\u0131\u011f\u0131n\u0131 tam (kesin) olarak ispatlamal\u0131d\u0131r.","Hakl\u0131l\u0131\u011f\u0131n\u0131 yakla\u015f\u0131k olarak ispat etmelidir.","Hi\xe7bir ispat y\xfck\xfc yoktur.","Yaln\u0131zca yemin etmesi yeterlidir."],t.s)
