B.EY=s(["Karar ge\xe7ersiz olur.","Karar \u015fekl\xee/maddi anlamda kesinle\u015fir ve icra edilebilir h\xe2le gelir.","Dava yeniden ilk derece mahkemesinde g\xf6r\xfcl\xfcr.","Karar resen Yarg\u0131tay\u2019a g\xf6nderilir."],t.s)
