B.G5=s(["Yine de t\xfcm giderleri \xf6der.","Yarg\u0131lama giderlerini \xf6demeye mahk\xfbm edilmez.","Giderlerin yar\u0131s\u0131n\u0131 \xf6der.","Dava reddedilir."],t.s)
B.Kw=new A.aX("taraf_06",B.bF,"Daval\u0131, davan\u0131n a\xe7\u0131lmas\u0131na kendi davran\u0131\u015f\u0131yla sebep olmam\u0131\u015f ve davac\u0131n\u0131n talebini ilk duru\u015fmada kabul etmi\u015fse yarg\u0131lama giderleri bak\u0131m\u0131ndan sonu\xe7 nedir?",B.G5,1,"HMK m. 312/2: Daval\u0131, davan\u0131n a\xe7\u0131lmas\u0131na kendi h\xe2l ve davran\u0131\u015f\u0131yla sebebiyet vermemi\u015f ve davac\u0131n\u0131n iddialar\u0131n\u0131 ilk duru\u015fmada kabul etmi\u015fse yarg\u0131lama giderlerini \xf6demeye mahk\xfbm edilmez.")
