B.Fd=s(["Tamamen ihtiyaridir, hi\xe7bir zorunluluk yoktur.","Arabulucuya ba\u015fvurulmu\u015f olmas\u0131 bir dava \u015fart\u0131d\u0131r.","Yaln\u0131zca taraflar isterse uygulan\u0131r ve dava a\xe7maya engel de\u011fildir.","Sadece toplu i\u015f uyu\u015fmazl\u0131klar\u0131nda zorunludur."],t.s)
B.K6=new A.aX("arabulucu_01",B.cN,"\u0130\u015f\xe7i-i\u015fveren aras\u0131ndaki kanuna/s\xf6zle\u015fmeye dayanan i\u015f\xe7ilik alaca\u011f\u0131 ve i\u015fe iade davalar\u0131nda arabuluculu\u011fun rol\xfc nedir?",B.Fd,1,"7036 say\u0131l\u0131 \u0130\u015f Mahkemeleri Kanunu m. 3: Kanuna, bireysel veya toplu i\u015f s\xf6zle\u015fmesine dayanan i\u015f\xe7i/i\u015fveren alaca\u011f\u0131, tazminat\u0131 ve i\u015fe iade taleplerinde arabulucuya ba\u015fvurulmu\u015f olmas\u0131 dava \u015fart\u0131d\u0131r.")
B.F2=s(["T\xfcm ticari davalar\u0131 istisnas\u0131z kapsar.","Konusu bir miktar paran\u0131n \xf6denmesi olan alacak ve tazminat taleplerini kapsar.","Yaln\u0131zca \u015firketler hukukundan do\u011fan davalar\u0131 kapsar.","Yaln\u0131zca kambiyo senetlerine ili\u015fkin davalar\u0131 kapsar."],t.s)
