B.G7=s(["Do\u011frudan davay\u0131 esastan reddeder.","Davac\u0131ya, son tutana\u011f\u0131n bir haftal\u0131k kesin s\xfcre i\xe7inde sunulmas\u0131 i\xe7in ihtarda bulunur; sunulmazsa dava usulden reddedilir.","Tutana\u011f\u0131 resen arabuluculuk b\xfcrosundan ister.","Davay\u0131 hi\xe7bir uyar\u0131 yapmadan g\xf6revsizlikle reddeder."],t.s)
B.Kn=new A.aX("arabulucu_04",B.cN,"Arabuluculuk dava \u015fart\u0131 olan bir davada, anla\u015fmaya var\u0131lamad\u0131\u011f\u0131na ili\u015fkin son tutanak dava dilek\xe7esine eklenmemi\u015fse mahkeme \xf6nce ne yapar?",B.G7,1,"7036 m. 3/2: Arabulucuya ba\u015fvurulmu\u015f ancak son tutanak eklenmemi\u015fse, mahkeme davac\u0131ya bir haftal\u0131k kesin s\xfcre verir; bu s\xfcre i\xe7inde sunulmazsa dava dilek\xe7esi kar\u015f\u0131 tarafa tebli\u011fe \xe7\u0131kar\u0131lmadan dava usulden reddedilir. (Hi\xe7 ba\u015fvurulmam\u0131\u015fsa s\xfcre verilmeden do\u011frudan reddedilir.)")
B.Gk=s(["K\u0131dem tazminat\u0131 talebi","Fazla mesai \xfccreti alaca\u011f\u0131","\u0130\u015f kazas\u0131 veya meslek hastal\u0131\u011f\u0131ndan kaynaklanan maddi-manevi tazminat davalar\u0131","\u0130hbar tazminat\u0131 talebi"],t.s)
B.Kf=new A.aX("arabulucu_05",B.cN,"A\u015fa\u011f\u0131dakilerden hangisi i\u015f hukukunda dava \u015fart\u0131 arabuluculu\u011fun kapsam\u0131 DI\u015eINDADIR?",B.Gk,2,"7036 m. 3: \u0130\u015f kazas\u0131 veya meslek hastal\u0131\u011f\u0131ndan kaynaklanan maddi-manevi tazminat davalar\u0131 ile bunlarla ilgili tespit, itiraz ve r\xfccu davalar\u0131 dava \u015fart\u0131 arabuluculu\u011fun kapsam\u0131 d\u0131\u015f\u0131ndad\u0131r.")
B.FW=s(["\xdc\xe7 hafta i\xe7inde; zorunlu h\xe2llerde en fazla bir hafta uzat\u0131labilir.","\u0130ki ay i\xe7inde; uzatma m\xfcmk\xfcn de\u011fildir.","Bir y\u0131l i\xe7inde.","S\xfcre \xf6ng\xf6r\xfclmemi\u015ftir."],t.s)
B.KC=new A.aX("arabulucu_06",B.cN,"Dava \u015fart\u0131 arabuluculukta arabulucu, ba\u015fvuru tarihinden itibaren s\xfcreci kural olarak ne kadar s\xfcrede tamamlamal\u0131d\u0131r?",B.FW,0,"\u0130\u015f ve ticari uyu\u015fmazl\u0131klarda arabulucu, g\xf6revlendirildi\u011fi tarihten itibaren s\xfcreci \xfc\xe7 hafta i\xe7inde sonu\xe7land\u0131r\u0131r; bu s\xfcre zorunlu h\xe2llerde arabulucu taraf\u0131ndan en fazla bir hafta uzat\u0131labilir.")
B.Ea=s(["Tan\u0131k","Senet","Yemin","Bilirki\u015fi"],t.s)
B.Kl=new A.aX("ispat_11",B.b0,"Hukuki i\u015flemlerin miktar veya de\u011feri kanunda \xf6ng\xf6r\xfclen s\u0131n\u0131r\u0131 ge\xe7ti\u011fi takdirde kural olarak hangi delille ispat edilmesi zorunludur?",B.Ea,1,"HMK m. 200 uyar\u0131nca, bir hakk\u0131n do\u011fumu, d\xfc\u015f\xfcr\xfclmesi, devri, de\u011fi\u015ftirilmesi, yenilenmesi, ertelenmesi, ikrar\u0131 ve itfas\u0131 amac\u0131yla yap\u0131lan hukuki i\u015flemlerin, yap\u0131ld\u0131klar\u0131 zamanki miktar veya de\u011ferleri kanunda \xf6ng\xf6r\xfclen s\u0131n\u0131r\u0131 ge\xe7ti\u011fi takdirde kural olarak senetle ispatlanmas\u0131 zorunludur.")
B.DP=s(["Karde\u015fler aras\u0131ndaki hukuki i\u015flemler","E\u015fler aras\u0131ndaki hukuki i\u015flemler","Ortaklar aras\u0131ndaki ticari i\u015flemler","Altsoy ile \xfcstsoy aras\u0131ndaki hukuki i\u015flemler"],t.s)
B.KE=new A.aX("ispat_12",B.b0,"A\u015fa\u011f\u0131dakilerden hangisi, senetle ispat zorunlulu\u011fu olan bir hukuki i\u015flemin miktar ne olursa olsun tan\u0131kla ispat edilebilece\u011fi istisnai hallerden (delil ba\u015flang\u0131c\u0131 aranmaks\u0131z\u0131n) biri de\u011fildir?",B.DP,2,"HMK m. 203 uyar\u0131nca altsoy-\xfcstsoy, karde\u015fler ve e\u015fler aras\u0131ndaki i\u015flemlerde miktar ne olursa olsun tan\u0131k dinlenebilir. Ortaklar aras\u0131ndaki i\u015flemler kural olarak bu istisnaya dahil edilmemi\u015ftir.")
B.iy=s(["1 hafta","2 hafta","3 hafta","4 hafta"],t.s)
B.K4=new A.aX("ispat_13",B.b0,"Taraflar, bilirki\u015fi raporunun kendilerine tebli\u011f tarihinden itibaren kural olarak ka\xe7 hafta i\xe7inde raporda eksik g\xf6rd\xfckleri hususlar\u0131n bilirki\u015fiye tamamlatt\u0131r\u0131lmas\u0131n\u0131 mahkemeden isteyebilirler?",B.iy,1,"HMK m. 281/1 uyar\u0131nca taraflar, bilirki\u015fi raporunun tebli\u011fi tarihinden itibaren iki hafta i\xe7inde raporda eksik veya belirsiz g\xf6rd\xfckleri hususlar\u0131n giderilmesini yahut yeni bir bilirki\u015fi atanmas\u0131n\u0131 isteyebilirler.")
B.Kh=new A.aX("gecici_08",B.bE,"Kar\u015f\u0131 taraf dinlenmeden (yoklu\u011funda) verilen ihtiyati tedbir kararlar\u0131na kar\u015f\u0131, itiraz hakk\u0131 olanlar karar\u0131n uygulanmas\u0131 s\u0131ras\u0131nda haz\u0131r bulunmuyorlarsa, tedbirin uygulanmas\u0131na ili\u015fkin tutana\u011f\u0131n tebli\u011finden itibaren en ge\xe7 ne kadar s\xfcre i\xe7inde itiraz edebilirler?",B.iy,0,"HMK m. 394/2 uyar\u0131nca kar\u015f\u0131 taraf dinlenmeden verilmi\u015f olan ihtiyati tedbir kararlar\u0131na itiraz s\xfcresi, karar\u0131n uyguland\u0131\u011f\u0131na ili\u015fkin tutana\u011f\u0131n tebli\u011finden itibaren bir haftad\u0131r.")
B.Fj=s(["\u0130htiyati tedbir","\u0130htiyati haciz","Delil tespiti","\u0130htiyari dava arkada\u015fl\u0131\u011f\u0131"],t.s)
B.Kv=new A.aX("gecici_09",B.bE,"G\xf6r\xfclmekte olan veya ileride a\xe7\u0131lacak bir davada ispat vas\u0131tas\u0131 olarak kullan\u0131lacak olan delillerin kaybolmas\u0131 veya g\xf6sterilmesinin \xe7ok zorla\u015fmas\u0131 ihtimali kar\u015f\u0131s\u0131nda ba\u015fvurulan ge\xe7ici hukuki koruma kurumu a\u015fa\u011f\u0131dakilerden hangisidir?",B.Fj,2,"HMK m. 400 uyar\u0131nca, taraflar hen\xfcz inceleme s\u0131ras\u0131 gelmemi\u015f olan veya ileride a\xe7\u0131lacak davada ileri s\xfcr\xfclecek delillerin kaybolaca\u011f\u0131 veya ileri s\xfcr\xfclmesinin zorla\u015faca\u011f\u0131 ihtimali varsa delil tespiti isteyebilir.")
B.Kk=new A.aX("kanun_08",B.bG,"Hukuk mahkemeleri taraf\u0131ndan verilen nihai kararlara kar\u015f\u0131, karar\u0131n usul\xfcne uygun tebli\u011finden itibaren kural olarak ka\xe7 hafta i\xe7inde istinaf yoluna ba\u015fvurulabilir?",B.iy,1,"HMK m. 345 uyar\u0131nca istinaf yoluna ba\u015fvuru s\xfcresi, karar\u0131n usul\xfcne uygun olarak taraflara tebli\u011finden itibaren iki haftad\u0131r.")
B.G6=s(["Miktar veya de\u011feri temyiz s\u0131n\u0131r\u0131n\u0131 a\u015fan alacak davalar\u0131","Soyba\u011f\u0131na ili\u015fkin kararlar","\xc7eki\u015fmesiz yarg\u0131 i\u015flerinde verilen kararlar","Ta\u015f\u0131nmaz \xfczerindeki ayni haklara ili\u015fkin kararlar"],t.s)
B.Kz=new A.aX("kanun_09",B.bG,"B\xf6lge adliye mahkemesi hukuk dairelerinden verilen a\u015fa\u011f\u0131daki kararlardan hangisine kar\u015f\u0131 kural olarak temyiz yoluna ba\u015fvurulamaz?",B.G6,2,"HMK m. 362/1-\xe7 bendine g\xf6re \xe7eki\u015fmesiz yarg\u0131 i\u015flerinde verilen b\xf6lge adliye mahkemesi kararlar\u0131 kesin olup bu kararlara kar\u015f\u0131 temyiz yoluna ba\u015fvurulamaz.")
B.Fp=s(["Feragat, h\xfck\xfcm kesinle\u015finceye kadar her zaman yap\u0131labilir.","Feragatin ge\xe7erlili\u011fi kar\u015f\u0131 taraf\u0131n veya mahkemenin kabul\xfcne ba\u011fl\u0131d\u0131r.","Feragat, kesin h\xfck\xfcm gibi hukuki sonu\xe7 do\u011furur.","\u015earta ba\u011fl\u0131 feragat kural olarak ge\xe7erli de\u011fildir."],t.s)
B.Ka=new A.aX("taraf_08",B.bF,'Davac\u0131n\u0131n talep sonucundan k\u0131smen veya tamamen vazge\xe7mesi olan "feragat" kurumu ile ilgili a\u015fa\u011f\u0131dakilerden hangisi yanl\u0131\u015ft\u0131r?',B.Fp,1,"HMK m. 309 uyar\u0131nca feragat ve kabul, kar\u015f\u0131 taraf\u0131n veya mahkemenin muvafakatine ba\u011fl\u0131 de\u011fildir; tek tarafl\u0131 irade beyan\u0131yla derhal sonu\xe7 do\u011furur.")
B.AN=new A.I(1,0.8941176470588236,0.6039215686274509,0.8235294117647058,B.h)
B.K3=new A.la("H\xfck\xfcm ve Kesin H\xfck\xfcm",B.AN,5,"hukumKesinHuku")
B.DH=s(["Sadece taraflar\u0131n\u0131n","Sadece dava sebeplerinin","Taraflar\u0131n\u0131n, dava sebeplerinin ve ilk davan\u0131n h\xfck\xfcm f\u0131kras\u0131 ile ikinci davan\u0131n talep sonucunun","Sadece mahkemelerinin"],t.s)
B.KI=new A.aX("hukum_01",B.K3,"Bir davada verilen karar\u0131n ba\u015fka bir davada maddi anlamda kesin h\xfck\xfcm te\u015fkil edebilmesi i\xe7in her iki davan\u0131n hangi unsurlar\u0131n\u0131n ayn\u0131 olmas\u0131 zorunludur?",B.DH,2,"HMK m. 303/1 uyar\u0131nca maddi anlamda kesin h\xfck\xfcmden s\xf6z edilebilmesi i\xe7in her iki davan\u0131n taraflar\u0131n\u0131n, dava sebeplerinin (vak\u0131alar\u0131n) ve ilk davan\u0131n h\xfck\xfcm f\u0131kras\u0131 ile ikinci davan\u0131n talep sonucunun ayn\u0131 olmas\u0131 gerekir.")
B.DK=s(["Eksikli\u011fi gidermesi i\xe7in davac\u0131ya bir haftal\u0131k kesin s\xfcre verir.","Davay\u0131 esastan reddeder.","Davay\u0131, dava \u015fart\u0131 yoklu\u011fu sebebiyle usulden reddeder.","Davay\u0131 durdurur ve taraflar\u0131 arabulucuya g\xf6nderir."],t.s)
B.K7=new A.aX("arabulucu_07",B.cN,"Kanunlarda arabuluculu\u011fa ba\u015fvurulmu\u015f olmas\u0131n\u0131n dava \u015fart\u0131 olarak \xf6ng\xf6r\xfcld\xfc\u011f\xfc durumlarda, davac\u0131 arabulucuya ba\u015fvurmadan do\u011frudan dava a\xe7arsa mahkeme nas\u0131l bir karar verir?",B.DK,2,"6325 say\u0131l\u0131 Hukuk Uyu\u015fmazl\u0131klar\u0131nda Arabuluculuk Kanunu m. 18/A-2 uyar\u0131nca, arabulucuya ba\u015fvurulmadan dava a\xe7\u0131ld\u0131\u011f\u0131n\u0131n anla\u015f\u0131lmas\u0131 halinde herhangi bir i\u015flem yap\u0131lmaks\u0131z\u0131n davan\u0131n, dava \u015fart\u0131 yoklu\u011fu sebebiyle usulden reddine karar verilir.")
